import React from 'react';
import { Card, Button, ListGroup, Badge } from 'react-bootstrap';

function Cart({ items, onRemoveItem, onClearCart }) {
  const total = items.reduce((sum, item) => sum + item.retailPrice * item.quantity, 0);

  if (items.length === 0) {
    return (
      <Card>
        <Card.Body className="text-center text-muted">
          <p>🛒 Корзина пуста</p>
        </Card.Body>
      </Card>
    );
  }

  return (
    <Card className="cart-sidebar">
      <Card.Header>
        <strong>Корзина</strong>
        <Badge bg="primary" pill className="float-end">{items.length}</Badge>
      </Card.Header>
      
      <ListGroup variant="flush">
        {items.map((item, index) => (
          <ListGroup.Item key={index} className="d-flex justify-content-between align-items-center">
            <div>
              <div className="fw-bold">{item.name}</div>
              <small className="text-muted">{item.brand} | {item.quantity} x {item.retailPrice.toFixed(2)} ₽</small>
            </div>
            <Button variant="outline-danger" size="sm" onClick={() => onRemoveItem(item.id)}>
              ✕
            </Button>
          </ListGroup.Item>
        ))}
      </ListGroup>
      
      <Card.Body>
        <h5 className="text-end mb-3">Итого: {total.toFixed(2)} ₽</h5>
        <Button variant="success" className="w-100 mb-2">Оформить заказ</Button>
        <Button variant="outline-danger" size="sm" className="w-100" onClick={onClearCart}>
          Очистить корзину
        </Button>
      </Card.Body>
    </Card>
  );
}

export default Cart;
